'use client';

import React, { useState, useEffect, useRef } from 'react';
import {
  X,
  Printer,
  User,
  Stethoscope,
  GraduationCap,
  Trophy,
  DollarSign,
  History,
  HelpCircle,
  Save,
  CheckCircle2,
  Circle,
  Edit,
  Plus,
  QrCode,
  Trash,
  Info,
  ExternalLink,
  Activity,
  MapPin,
} from 'lucide-react';
import { toast } from 'sonner';
import { getSystemSettings, updateSystemSettings, SystemSettings } from '@/src/services/settingsService';
import { getCities, City } from '@/src/services/cityService';
import { getCourses } from '@/src/services/courseService';
import {
  getLicenseCategories,
  updateStudent,
  getStudentById,
  getStudentHistory,
  getLeads,
} from '@/src/services/studentService';
import { getExamsByStudent } from '@/src/services/examService';
import { getPaymentsByStudent, createPayment, updatePayment } from '@/src/services/paymentService';
import { useAuth } from '@/src/context/AuthContext';
import CourseSelectDropdown from '@/src/components/shared/CourseSelectDropdown';
import ViDateInput from '@/src/components/shared/ViDateInput';
import DatSessionModal from './modules/DatSessionModal';
import { numberToVietnameseWords, formatNumberWithDots, parseNumberFromDots } from '@/src/utils/currencyUtils';

interface Student {
  id: string;
  name: string;
  phone: string;
  rank: string;
  region: string;
  status: string;
}

interface StudentDetailDrawerProps {
  isOpen: boolean;
  onClose: () => void;
  student: Student | null;
  defaultTab?: string;
  onRefresh?: () => void;
}

interface PaymentFormData {
  date: string;
  amount: string;
  stage: string;
  method: string;
  receipt: string;
}

const initialPaymentState: PaymentFormData = {
  date: new Date().toISOString().split('T')[0],
  amount: '',
  stage: '',
  method: 'Tiền mặt',
  receipt: '',
};

const FieldWrapper = ({
  label,
  required,
  children,
  colSpan = 1,
  error,
  touched,
}: {
  label: string;
  required?: boolean;
  children: React.ReactNode;
  colSpan?: number;
  error?: string;
  touched?: boolean;
}) => {
  const hasError = touched && error;

  return (
    <div className={`flex flex-col gap-1.5 ${colSpan === 2 ? 'col-span-2' : colSpan === 3 ? 'col-span-3' : ''}`}>
      <div className="flex items-center justify-between px-0.5">
        <label
          className={`text-[10px] font-extrabold uppercase tracking-tight flex items-center gap-1 ${hasError ? 'text-rose-500' : 'text-gray-500'}`}
        >
          {label} {required && <span className="text-rose-500">*</span>}
        </label>
        <HelpCircle className="w-3.5 h-3.5 text-gray-300 hover:text-primary transition-colors cursor-help" />
      </div>
      {children}
      {hasError && (
        <p className="text-[10px] text-rose-500 font-bold animate-in fade-in slide-in-from-top-1 ml-1">{error}</p>
      )}
    </div>
  );
};

const StudentDetailDrawer: React.FC<StudentDetailDrawerProps> = ({
  isOpen,
  onClose,
  student,
  defaultTab = 'hoso',
  onRefresh,
}) => {
  const [activeTab, setActiveTab] = useState(defaultTab);
  const [isDatModalOpen, setIsDatModalOpen] = useState(false);
  const [paymentForm, setPaymentForm] = useState<PaymentFormData>({
    ...initialPaymentState,
  });
  const [paymentErrors, setPaymentErrors] = useState<Partial<Record<keyof PaymentFormData, string>>>({});
  const [paymentTouched, setPaymentTouched] = useState<Partial<Record<keyof PaymentFormData, boolean>>>({});
  const [profileErrors, setProfileErrors] = useState<Record<string, string>>({});
  const [profileTouched, setProfileTouched] = useState<Record<string, boolean>>({});

  // Metadata States
  const [settings, setSettings] = useState<SystemSettings | null>(null);
  const [cities, setCities] = useState<City[]>([]);
  const [courses, setCourses] = useState<any[]>([]);
  const [licenseCats, setLicenseCats] = useState<any[]>([]);
  const [fullData, setFullData] = useState<any>(null);
  const [selectedRank, setSelectedRank] = useState<string>('');
  const [selectedCity, setSelectedCity] = useState<string>('');
  const [selectedCourse, setSelectedCourse] = useState<string>('');
  const [selectedDob, setSelectedDob] = useState<string>('');
  const [selectedEnrollmentDate, setSelectedEnrollmentDate] = useState<string>('');
  const [exams, setExams] = useState<any[]>([]);
  const [paymentHistory, setPaymentHistory] = useState<any[]>([]);
  const [systemHistory, setSystemHistory] = useState<any[]>([]);
  const [leads, setLeads] = useState<any[]>([]);
  const [selectedLead, setSelectedLead] = useState<string>('');
  const [isSubmittingPayment, setIsSubmittingPayment] = useState(false);
  const [hospitalModalOpen, setHospitalModalOpen] = useState(false);
  const [hospitalDraft, setHospitalDraft] = useState('');
  const [hospitalAddressDraft, setHospitalAddressDraft] = useState('');
  const [healthCheckState, setHealthCheckState] = useState({
    status: 'Chờ khám',
    date: '',
    hospital: '',
    hospitalAddress: '',
    note: '',
  });
  const [healthCheckErrors, setHealthCheckErrors] = useState<Record<string, string>>({});
  const [healthCheckTouched, setHealthCheckTouched] = useState<Record<string, boolean>>({});
  const [currentFee, setCurrentFee] = useState<string>('');
  const [isFeeManuallySet, setIsFeeManuallySet] = useState(false);
  const [editingPaymentId, setEditingPaymentId] = useState<string | null>(null);
  const [paymentToPrint, setPaymentToPrint] = useState<any | null>(null);
  const [isPrintingProfile, setIsPrintingProfile] = useState(false);
  const printableRef = useRef<HTMLDivElement>(null);

  const getStatusBadgeStyle = (status: string, courseId?: string, endDate?: string) => {
    let currentStatus = status;

    // Management Logical Mapping - ONLY automatically override to "Đã vào khóa" if course is assigned
    if (courseId) {
      if (
        !currentStatus ||
        ['Chờ KSK', 'Đã KSK', 'Đã nộp HS', 'Nộp HS', 'Chờ xếp khóa', 'Chưa vào khóa', 'Học viên tồn'].includes(
          currentStatus,
        )
      ) {
        currentStatus = 'Đã vào khóa';
      }
    }

    if (
      currentStatus &&
      (currentStatus.startsWith('Đang học') || currentStatus === 'Nộp HS') &&
      endDate &&
      new Date(endDate) < new Date()
    ) {
      currentStatus = 'Đang thi';
    }

    if (currentStatus === 'Chờ KSK') return 'bg-orange-50 text-orange-600 border-orange-200';
    if (currentStatus === 'Đã KSK') return 'bg-blue-50 text-blue-600 border-blue-200';
    if (currentStatus?.includes('nộp HS') || currentStatus === 'Nộp HS')
      return 'bg-indigo-50 text-indigo-600 border-indigo-200';
    if (currentStatus === 'Chờ xếp khóa') return 'bg-amber-50 text-amber-600 border-amber-200';
    if (currentStatus === 'Chưa vào khóa') return 'bg-sky-50 text-sky-600 border-sky-200';
    if (currentStatus === 'Đã vào khóa') return 'bg-emerald-50 text-emerald-700 border-emerald-200';
    if (currentStatus === 'Học viên tồn') return 'bg-slate-50 text-slate-700 border-slate-300';
    if (currentStatus?.startsWith('Đang học')) return 'bg-indigo-50 text-indigo-700 border-indigo-200';
    if (currentStatus === 'Đang thi' || currentStatus?.includes('Thi'))
      return 'bg-purple-50 text-purple-600 border-purple-200';
    if (currentStatus === 'Đã đậu') return 'bg-emerald-50 text-emerald-600 border-emerald-200';
    if (currentStatus === 'Thi lại') return 'bg-rose-50 text-rose-600 border-rose-200';
    if (currentStatus === 'Nghỉ học') return 'bg-gray-50 text-gray-600 border-gray-200';
    return 'bg-gray-50 text-gray-500 border-gray-200';
  };

  const getStatusLabel = (status: string, courseId?: string, endDate?: string) => {
    let currentStatus = status;

    // Management Logical Mapping - ONLY automatically override to "Đã vào khóa" if course is assigned
    if (courseId) {
      if (
        !currentStatus ||
        ['Chờ KSK', 'Đã KSK', 'Đã nộp HS', 'Nộp HS', 'Chờ xếp khóa', 'Chưa vào khóa', 'Học viên tồn'].includes(
          currentStatus,
        )
      ) {
        currentStatus = 'Đã vào khóa';
      }
    }

    if (
      currentStatus &&
      (currentStatus.startsWith('Đang học') || currentStatus === 'Nộp HS') &&
      endDate &&
      new Date(endDate) < new Date()
    ) {
      currentStatus = 'Đang thi';
    }
    return (currentStatus || '').toUpperCase();
  };

  const currentStatusValue = fullData?.status_detail || student?.status;
  const currentCourseEndDate = fullData?.enrollment?.course_end_date;

  const handleDatSuccess = async () => {
    // Refresh student data to get updated stats
    try {
      const studentId = student?.id || (student as any)?._id;
      if (studentId) {
        const res = await getStudentById(studentId);
        if (res.success) setFullData(res.data);
      }
      // Notify parent to refresh list/analytics
      onRefresh?.();
    } catch (e) {
      console.error('Error refreshing student data:', e);
    }
  };

  // Sync tab when drawer opens
  React.useEffect(() => {
    if (isOpen) {
      setActiveTab(defaultTab);
    }
  }, [isOpen, defaultTab]);

  // Combined fetch of settings, cities, courses, and license categories
  useEffect(() => {
    let cancelled = false;
    if (isOpen) {
      Promise.all([
        getSystemSettings().catch(() => ({})),
        getCities().catch(() => ({})),
        getCourses(1, 100, { status: 'Sắp khai giảng' }).catch(() => ({})),
        getLicenseCategories().catch(() => ({})),
        getLeads().catch(() => ({})),
      ]).then(([settingsRes, citiesRes, coursesRes, licenseRes, leadsRes]) => {
        if (cancelled) return;
        if (settingsRes?.success) setSettings(settingsRes.data);
        if (citiesRes?.success) setCities(citiesRes.data?.data || citiesRes.data || []);
        if (coursesRes?.success) setCourses(coursesRes.data?.docs || coursesRes.data?.data || coursesRes.data || []);
        if (licenseRes?.success) setLicenseCats(licenseRes.data?.data || licenseRes.data || []);
        if (leadsRes?.success) setLeads(leadsRes.data || []);
      });
    }
    return () => { cancelled = true; };
  }, [isOpen]);

  // Fetch student-specific data (full profile, exams, payments, history)
  useEffect(() => {
    let cancelled = false;
    const fetchData = async () => {
      const studentId = student?.id || (student as any)?._id;
      if (!isOpen || !studentId) return;

      try {
        // Fetch profile
        const profileRes = await getStudentById(studentId);
        if (cancelled) return;
        if (profileRes.success) {
          setFullData(profileRes.data);
        } else {
          setFullData({});
        }

        // Fetch related lists
        const [examRes, paymentRes, historyRes] = await Promise.all([
          getExamsByStudent(studentId).catch(() => ({})),
          getPaymentsByStudent(studentId).catch(() => ({})),
          getStudentHistory(studentId, 1, 50).catch(() => ({})),
        ]);

        if (cancelled) return;
        if (examRes?.success) setExams(examRes.data || []);
        if (paymentRes?.success) setPaymentHistory(paymentRes.data?.data || paymentRes.data || []);
        if (historyRes?.success) setSystemHistory(historyRes.data?.data || historyRes.data || []);
      } catch (error) {
        if (!cancelled) {
          console.error('Lỗi tải thông tin chi tiết học viên:', error);
          setFullData({});
        }
      }
    };

    if (isOpen) {
      fetchData();
    } else {
      setFullData(null);
      setSelectedRank('');
      setSelectedCity('');
      setSelectedCourse('');
      setSelectedDob('');
      setSelectedEnrollmentDate('');
    }
    return () => { cancelled = true; };
  }, [isOpen, student?.id]);

  // Update controlled values when fullData changes
  useEffect(() => {
    if (fullData) {
      if (fullData.license_category_id) {
        setSelectedRank(
          typeof fullData.license_category_id === 'string'
            ? fullData.license_category_id
            : (fullData.license_category_id as any)._id,
        );
      } else if (fullData.rank && licenseCats.length > 0) {
        // Try fallback if rank name is present
        const found = licenseCats.find((c) => c.name === fullData.rank || c.code === fullData.rank);
        if (found) setSelectedRank(found._id);
      }

      if (fullData.region_id) {
        setSelectedCity(typeof fullData.region_id === 'string' ? fullData.region_id : (fullData.region_id as any)._id);
      } else if (fullData.region_name && cities.length > 0) {
        const foundCity = cities.find((c) => c.name === fullData.region_name);
        if (foundCity) setSelectedCity(foundCity._id);
      }

      const courseId = fullData.course_id || fullData.enrollment?.course_id;
      if (courseId) {
        setSelectedCourse(typeof courseId === 'string' ? courseId : (courseId as any)._id);
      } else {
        setSelectedCourse('');
      }

      const leadManager = fullData.lead_manager;
      if (leadManager) {
        setSelectedLead(leadManager);
      } else {
        setSelectedLead('');
      }

      if (fullData.user_id?.dob) {
        setSelectedDob(new Date(fullData.user_id.dob).toISOString().split('T')[0]);
      } else {
        setSelectedDob('');
      }

      if (fullData.created_at) {
        setSelectedEnrollmentDate(new Date(fullData.created_at).toISOString().split('T')[0]);
      } else {
        setSelectedEnrollmentDate('');
      }

      if (fullData.health_check) {
        setHealthCheckState({
          status: fullData.health_check.status || 'Chờ khám',
          date: fullData.health_check.date ? new Date(fullData.health_check.date).toISOString().split('T')[0] : '',
          hospital: fullData.health_check.hospital || '',
          hospitalAddress: fullData.health_check.hospital_address || '',
          note: fullData.health_check.note || '',
        });
      } else {
        setHealthCheckState({
          status: 'Chờ khám',
          date: '',
          hospital: '',
          hospitalAddress: '',
          note: '',
        });
      }

      const feeValue =
        fullData.enrollment?.fee ||
        fullData.fee ||
        (typeof fullData.course_id === 'object' && fullData.course_id !== null
          ? (fullData.course_id as any).course_fee
          : undefined);

      if (feeValue !== undefined) {
        setCurrentFee(formatNumberWithDots(feeValue.toString()));
      }
      setIsFeeManuallySet(false);
    }
  }, [fullData]);

  // Sync rank ID when categories load if not yet set
  React.useEffect(() => {
    if (licenseCats.length > 0 && student?.rank && !selectedRank && !fullData?.license_category_id) {
      const found = licenseCats.find((c) => c.name === student.rank || c.code === student.rank);
      if (found) setSelectedRank(found._id);
    }
  }, [licenseCats, student?.rank, selectedRank, fullData]);

  const isFieldRequired = (fieldName: string) => {
    return settings?.requiredFields?.includes(fieldName) ?? false;
  };

  const validateProfile = (data: any) => {
    const errs: Record<string, string> = {};
    const requiredConfig = settings?.requiredFields || [];

    // Tổng học phí (tuition/fee) is always optional — auto-filled from course or left blank
    const activeRequired = requiredConfig.filter(
      (f: string) => f !== 'tuition' && f !== 'fee'
    );

    activeRequired.forEach((f: string) => {
      const keyMap: Record<string, string> = { cccd: 'identity_number' };
      const payloadKey = keyMap[f] || f;

      if (f === 'address') {
        if (!data.city && !data.region_id) errs.city = 'Vui lòng chọn khu vực tuyển sinh (Tỉnh/Thành phố).';
        if (!data.address?.trim()) errs.address = 'Vui lòng nhập địa chỉ chi tiết.';
      } else if (f === 'region' || f === 'city') {
        if (!data.city && !data.region_id) errs[f] = 'Vui lòng chọn khu vực tuyển sinh (Tỉnh/Thành phố).';
      } else {
        if (!data[payloadKey] || (typeof data[payloadKey] === 'string' && !data[payloadKey].trim())) {
          const labels: Record<string, string> = {
            name: 'Họ và tên',
            dob: 'Ngày sinh',
            phone: 'Số điện thoại',
            cccd: 'Số CCCD',
            rank: 'Hạng bằng',
            course: 'Khóa học',
            region: 'Khu vực tuyển sinh',
            city: 'Tỉnh/Thành phố',
            address: 'Địa chỉ chi tiết'
          };
          const action = (f === 'rank' || f === 'course' || f === 'region' || f === 'city') ? 'chọn' : 'nhập';
          errs[f] = `Vui lòng ${action} ${labels[f] || f}.`;
        }
      }
    });

    if (data.lead_id) {
      // Optional: add validation if needed
    }

    // Format validation
    if (data.phone && !/^\d{10}$/.test(data.phone.trim())) {
      errs.phone = 'Số điện thoại phải có đúng 10 chữ số.';
    }
    if (data.identity_number && !/^\d{12}$/.test(data.identity_number.trim())) {
      errs.cccd = 'Số CCCD phải có đúng 12 chữ số.';
    }

    return errs;
  };

  const { user } = useAuth();

  const validateHealthCheck = (data = healthCheckState) => {
    const errs: Record<string, string> = {};
    const isNotPending = data.status !== 'Chờ khám';

    if (isNotPending && !data.date.trim()) {
      errs.date = 'Vui lòng nhập ngày khám.';
    }
    if (isNotPending && !data.hospital.trim()) {
      errs.hospital = 'Vui lòng nhập phòng khám / bệnh viện.';
    }

    setHealthCheckErrors(errs);
    return errs;
  };

  // Fetch settings if not loaded (for clinic_list)
  useEffect(() => {
    if (!settings) {
      let cancelled = false;
      getSystemSettings().then((res: any) => {
        if (!cancelled && res?.success) setSettings(res.data);
      });
      return () => { cancelled = true; };
    }
  }, [settings]);

  if (!isOpen || !student) return null;

  const handlePaymentChange = (field: keyof PaymentFormData, value: string) => {
    let finalValue = value;
    if (field === 'amount') {
      finalValue = formatNumberWithDots(value);
    }
    const updated = { ...paymentForm, [field]: finalValue };
    setPaymentForm(updated);
    if (paymentTouched[field]) {
      setPaymentErrors(validatePayment(updated));
    }
  };

  const validatePayment = (data: PaymentFormData) => {
    const errs: Partial<Record<keyof PaymentFormData, string>> = {};
    if (!data.date) errs.date = 'Ngày đóng không được để trống.';
    if (!data.amount || !data.amount.trim()) errs.amount = 'Vui lòng nhập số tiền.';
    else {
      const rawAmount = parseNumberFromDots(data.amount);
      if (isNaN(Number(rawAmount)) || Number(rawAmount) <= 0) errs.amount = 'Số tiền phải là số hợp lệ.';
    }
    if (!data.receipt.trim()) errs.receipt = 'Mã biên lai không được để trống.';
    return errs;
  };

  const handlePrintPayment = (p: any) => {
    setPaymentToPrint(p);
    // Timeout to allow state to render the print view before printing
    setTimeout(() => {
      window.print();
    }, 100);
  };

  const handlePaymentSubmit = async () => {
    const allTouched = Object.keys(paymentForm).reduce((acc, key) => ({ ...acc, [key]: true }), {});
    setPaymentTouched(allTouched);

    const errs = validatePayment(paymentForm);
    setPaymentErrors(errs);

    if (Object.keys(errs).length > 0) {
      toast.error('Vui lòng điền đầy đủ thông tin thanh toán!');
      return;
    }

    const courseStudentId = fullData?.enrollment?._id;
    if (!courseStudentId) {
      toast.error('Học viên chưa được đăng ký khóa học nào!');
      return;
    }

    setIsSubmittingPayment(true);
    try {
      const stageMap: Record<string, string> = {
        'Đăng ký ban đầu': 'tuition_fee',
        'Học thực hành': 'practice_completed',
        'Thi hết môn': 'graduation_exam',
        'Thi sát hạch': 're_exam_fee',
      };

      const payload = {
        course_student_id: courseStudentId,
        payment_date: new Date(paymentForm.date).toISOString(),
        type: stageMap[paymentForm.stage] || 'other',
        is_received: true,
        received_fee: Number(parseNumberFromDots(paymentForm.amount)),
        note: paymentForm.receipt,
        stage_name: paymentForm.stage,
      };

      let res;
      if (editingPaymentId) {
        res = await updatePayment(editingPaymentId, {
          payment_date: payload.payment_date,
          received_fee: payload.received_fee,
          note: payload.note,
          stage_name: payload.stage_name,
        });
      } else {
        res = await createPayment(payload);
      }

      if (res.success) {
        toast.success(
          editingPaymentId
            ? `Đã cập nhật lịch sử đóng tiền thành công!`
            : `Đã ghi nhận đóng ${paymentForm.amount}đ thành công cho ${student.name}!`,
        );

        // Auto print
        handlePrintPayment({
          ...payload,
          _id: editingPaymentId || res.data?._id || 'NEW',
          payment_date: payload.payment_date,
          received_fee: payload.received_fee,
        });

        setPaymentForm({ ...initialPaymentState });
        setEditingPaymentId(null);
        setPaymentErrors({});
        setPaymentTouched({});

        // Refresh payment history & full data
        const studentId = student.id || (student as any)._id;
        const [paymentRes, fullDataRes] = await Promise.all([
          getPaymentsByStudent(studentId),
          getStudentById(studentId),
        ]);
        if (paymentRes.success) setPaymentHistory(paymentRes.data?.data || []);
        if (fullDataRes.success) setFullData(fullDataRes.data);
      } else {
        toast.error(res.message || 'Lỗi khi lưu giao dịch');
      }
    } catch (error) {
      console.error(error);
      toast.error('Có lỗi xảy ra, vui lòng thử lại sau.');
    } finally {
      setIsSubmittingPayment(false);
    }
  };

  const handleEditPayment = (p: any) => {
    const stageMapReverse: Record<string, string> = {
      tuition_fee: 'Đăng ký ban đầu',
      practice_completed: 'Học thực hành',
      graduation_exam: 'Thi hết môn',
      re_exam_fee: 'Thi sát hạch',
    };

    setEditingPaymentId(p._id);
    setPaymentForm({
      date: new Date(p.payment_date).toISOString().split('T')[0],
      amount: formatNumberWithDots(p.received_fee.toString()),
      // Ưu tiên stage_name (tên động từ settings), fallback về reverse map của type cũ
      stage: p.stage_name || stageMapReverse[p.type] || '',
      method: p.method || 'Tiền mặt',
      receipt: p.note || '',
    });
    setPaymentErrors({});
    setPaymentTouched({});
    setActiveTab('hocphi');

    // Cuộn tới form đóng tiền
    const formEl = document.getElementById('add-payment-form');
    if (formEl) formEl.scrollIntoView({ behavior: 'smooth' });
  };

  const getPaymentInputClass = (field: keyof PaymentFormData) => {
    const hasError = paymentTouched[field] && paymentErrors[field];
    return `w-full px-3 py-2.5 bg-white border rounded-xl text-sm font-medium transition-all focus:outline-none focus:ring-4 ${
      hasError
        ? 'border-rose-300 focus:ring-rose-500/10 focus:border-rose-500 bg-rose-50/20'
        : 'border-gray-200 focus:ring-indigo-500/10 focus:border-indigo-500'
    }`;
  };

  const tabs = [
    { id: 'hoso', label: 'Hồ sơ', icon: User },
    { id: 'khamsk', label: 'Khám SK', icon: Stethoscope },
    { id: 'tiendo', label: 'Tiến độ học', icon: GraduationCap },
    { id: 'sathach', label: 'Sát hạch & KQ', icon: Trophy },
    { id: 'hocphi', label: 'Học phí', icon: DollarSign },
    ...(user?.role === 'admin' ? [{ id: 'lichsu', label: 'Lịch sử', icon: History }] : []),
  ];

  return (
    <div className="fixed inset-0 z-50 overflow-hidden">
      {/* Backdrop */}
      <div
        className={`absolute inset-0 bg-gray-900/40 backdrop-blur-sm transition-opacity duration-300 ${isOpen ? 'opacity-100' : 'opacity-0'}`}
        onClick={onClose}
      />

      {/* Drawer */}
      <div
        className={`absolute inset-y-0 right-0 max-w-[650px] w-full bg-white shadow-2xl flex flex-col transform transition-transform duration-300 ease-in-out ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}
      >
        {/* Header Profile */}
        <div className="px-6 py-5 border-b border-gray-100 bg-white flex items-start justify-between">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 rounded-full bg-indigo-600 flex items-center justify-center text-white text-xl font-bold shadow-md shadow-indigo-600/20 shrink-0">
              {fullData?.user_id?.last_name?.[0] || student.name?.charAt(0) || 'H'}
            </div>
            <div>
              <h2 className="text-xl font-extrabold text-gray-900">
                {fullData?.user_id?.last_name
                  ? `${fullData.user_id.last_name} ${fullData.user_id.first_name}`
                  : student.name || 'Học viên'}
              </h2>
              <div className="flex flex-wrap items-center gap-2 mt-1">
                <span className="px-1.5 py-0.5 rounded bg-indigo-50 text-indigo-700 text-[10px] font-black border border-indigo-100 uppercase">
                  {fullData?.student_code || 'Chưa có mã'}
                </span>
                <span className="px-1.5 py-0.5 rounded bg-blue-50 text-blue-700 text-[10px] font-black border border-blue-100">
                  {fullData?.license_category_code ||
                    fullData?.license_category_name ||
                    student.rank ||
                    'Chưa xác định'}
                </span>
                <span className="text-[11px] text-gray-500 font-medium">
                  {fullData?.region_id?.name || fullData?.user_id?.address?.split(',').pop()?.trim() || student.region}
                </span>
                <span className="text-[11px] text-gray-400">•</span>
                <span className="text-[11px] text-gray-500 font-bold">{fullData?.user_id?.phone || student.phone}</span>
              </div>
            </div>
          </div>
          {/* Backdrop */}
          <div
            className={`absolute inset-0 bg-gray-900/40 backdrop-blur-sm transition-opacity duration-300 ${isOpen ? 'opacity-100' : 'opacity-0'}`}
            onClick={onClose}
          />

          {/* Drawer */}
          <div
            className={`absolute inset-y-0 right-0 max-w-[650px] w-full bg-white shadow-2xl flex flex-col transform transition-transform duration-300 ease-in-out ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}
          >
            {/* Header Profile */}
            <div className="px-6 py-5 border-b border-gray-100 bg-white flex items-start justify-between">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 rounded-full bg-indigo-600 flex items-center justify-center text-white text-xl font-bold shadow-md shadow-indigo-600/20 shrink-0">
                  {fullData?.user_id?.last_name?.[0] || student.name?.charAt(0) || 'H'}
                </div>
                <div>
                  <h2 className="text-xl font-extrabold text-gray-900">
                    {fullData?.user_id?.last_name
                      ? `${fullData.user_id.last_name} ${fullData.user_id.first_name}`
                      : student.name || 'Học viên'}
                  </h2>
                  <div className="flex flex-wrap items-center gap-2 mt-1">
                    <span className="px-1.5 py-0.5 rounded bg-blue-50 text-blue-700 text-[10px] font-black border border-blue-100">
                      {fullData?.license_category_code ||
                        fullData?.license_category_name ||
                        student.rank ||
                        'Chưa xác định'}
                    </span>
                    <span className="text-[11px] text-gray-500 font-medium">
                      {fullData?.region_id?.name ||
                        fullData?.user_id?.address?.split(',').pop()?.trim() ||
                        student.region}
                    </span>
                    <span className="text-[11px] text-gray-400">•</span>
                    <span className="text-[11px] text-gray-500 font-bold">
                      {fullData?.user_id?.phone || student.phone}
                    </span>
                  </div>
                </div>
              </div>
              <div className="flex items-center gap-2 shrink-0">
                {currentStatusValue && (
                  <span
                    className={`px-3 py-1 rounded-lg text-xs font-bold mr-2 border ${getStatusBadgeStyle(currentStatusValue, fullData?.enrollment?.course_id || fullData?.course_id, currentCourseEndDate)}`}
                  >
                    {getStatusLabel(
                      currentStatusValue,
                      fullData?.enrollment?.course_id || fullData?.course_id,
                      currentCourseEndDate,
                    )}
                  </span>
                )}
                <button
                  onClick={() => {
                    setIsPrintingProfile(true);
                    setTimeout(() => {
                      window.print();
                      setIsPrintingProfile(false);
                    }, 100);
                  }}
                  title="Xuất mẫu in hồ sơ"
                  className="p-2 text-indigo-600 hover:text-indigo-700 hover:bg-indigo-50 rounded-lg transition-colors border border-indigo-200 bg-white"
                >
                  <Printer className="w-4 h-4" />
                </button>
                <button
                  onClick={onClose}
                  className="p-2 text-gray-400 hover:text-rose-500 hover:bg-rose-50 rounded-lg transition-colors border border-gray-200"
                >
                  <X className="w-4 h-4" />
                </button>
              </div>
            </div>

            {/* Tabs */}
            <div className="flex overflow-x-auto hide-scrollbar border-b border-gray-100 px-2 bg-gray-50/50">
              {tabs.map((tab) => {
                const Icon = tab.icon;
                const isActive = activeTab === tab.id;
                return (
                  <button
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id)}
                    className={`flex items-center gap-2 px-4 py-3 text-xs font-bold border-b-2 transition-colors whitespace-nowrap ${
                      isActive
                        ? 'border-indigo-600 text-indigo-700 bg-indigo-50/30'
                        : 'border-transparent text-gray-500 hover:text-gray-700 hover:bg-gray-50'
                    }`}
                  >
                    <Icon className="w-4 h-4" />
                    {tab.label}
                  </button>
                );
              })}
            </div>

            {/* Scrollable Form Content */}
            <div className="flex-1 overflow-y-auto px-6 py-6 hide-scrollbar bg-white">
              {/* TAB: HỒ SƠ */}
              {activeTab === 'hoso' &&
                (!fullData ? (
                  <div className="flex justify-center items-center h-40">
                    <div className="w-8 h-8 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin"></div>
                  </div>
                ) : (
                  <form
                    key={fullData?._id || student.id || 'loading'}
                    id="hoso-form"
                    onSubmit={async (e) => {
                      e.preventDefault();
                      const form = e.target as HTMLFormElement;

                      const phone = (form.elements.namedItem('phone') as HTMLInputElement)?.value;
                      const cccd = (form.elements.namedItem('cccd') as HTMLInputElement)?.value;

                      if (phone && !/^\d{10}$/.test(phone.trim())) {
                        toast.error('Số điện thoại phải có đúng 10 chữ số.');
                        return;
                      }
                      if (cccd && !/^\d{12}$/.test(cccd.trim())) {
                        toast.error('Số CCCD phải có đúng 12 chữ số.');
                        return;
                      }

                      // Construct payload
                      const payload = {
                        name: (form.elements.namedItem('name') as HTMLInputElement)?.value,
                        dob: selectedDob,
                        gender: (form.elements.namedItem('gender') as HTMLSelectElement)?.value,
                        phone,
                        identity_number: cccd,
                        identity_card: cccd, // Standardized for backend compatibility
                        rank: selectedRank,
                        license_category_id: selectedRank,
                        city: selectedCity,
                        region_id: selectedCity,
                        address: (form.elements.namedItem('address') as HTMLInputElement)?.value,
                        course: selectedCourse,
                        enrollment_date: selectedEnrollmentDate,
                        referrer: (form.elements.namedItem('referrer') as HTMLInputElement)?.value,
                        status: (form.elements.namedItem('status') as HTMLSelectElement)?.value,
                        status_detail: selectedCourse ? 'Đã vào khóa' : 'Chờ KSK',
                        fee: Number(parseNumberFromDots(currentFee || '0')),
                        lead_manager: selectedLead || null,
                        note: (form.elements.namedItem('note') as HTMLTextAreaElement)?.value,
                      };

                      // Validate using the new helper
                      const errs = validateProfile(payload);
                      setProfileErrors(errs);

                      // Mark all required fields as touched to show errors if any
                      const touchedState: Record<string, boolean> = {};
                      (settings?.requiredFields || []).forEach((f) => (touchedState[f] = true));
                      if (errs.city || errs.address) {
                        touchedState.city = true;
                        touchedState.address = true;
                      }
                      setProfileTouched((prev) => ({ ...prev, ...touchedState }));

                      if (Object.keys(errs).length > 0) {
                        const firstError = Object.values(errs)[0];
                        toast.error(firstError || 'Vui lòng kiểm tra lại thông tin!');
                        return;
                      }

                      try {
                        const submitBtn = form.querySelector('button[type="submit"]') as HTMLButtonElement;
                        if (submitBtn) submitBtn.disabled = true;
                        const res = await updateStudent(student.id, payload);
                        if (res.success) {
                          toast.success('Đã ghi nhận thay đổi hồ sơ.');
                          onRefresh?.();
                          onClose();
                        } else {
                          toast.error(res.message || res.error || 'Có lỗi xảy ra khi lưu học viên.');
                        }
                      } catch (err: any) {
                        toast.error(err?.message || 'Lỗi khi lưu thông tin. Vui lòng thử lại sau.');
                      } finally {
                        const submitBtn = form.querySelector('button[type="submit"]') as HTMLButtonElement;
                        if (submitBtn) submitBtn.disabled = false;
                      }
                    }}
                    className="grid grid-cols-2 gap-x-6 gap-y-5 animate-in fade-in slide-in-from-bottom-2 duration-300"
                  >
                    <FieldWrapper
                      label="Họ và tên"
                      required={isFieldRequired('name')}
                      error={profileErrors.name}
                      touched={profileTouched.name}
                    >
                      <input
                        name="name"
                        required={isFieldRequired('name')}
                        type="text"
                        defaultValue={
                          fullData?.user_id?.last_name
                            ? `${fullData.user_id.last_name} ${fullData.user_id.first_name}`
                            : student.name
                        }
                        onBlur={() => setProfileTouched((prev) => ({ ...prev, name: true }))}
                        onChange={(e) => {
                          const val = e.target.value;
                          if (profileTouched.name) {
                            setProfileErrors((prev) => ({
                              ...prev,
                              name: val.trim() ? '' : 'Vui lòng nhập Họ và tên.',
                            }));
                          }
                        }}
                        className={`w-full px-3 py-2.5 bg-white border rounded-xl focus:outline-none focus:ring-4 transition-all ${
                          profileTouched.name && profileErrors.name
                            ? 'border-rose-300 focus:ring-rose-500/10 focus:border-rose-500 bg-rose-50/20'
                            : 'border-gray-200 focus:ring-indigo-500/10 focus:border-indigo-500'
                        } text-sm font-medium`}
                      />
                    </FieldWrapper>
                    <FieldWrapper
                      label="Ngày sinh"
                      required={isFieldRequired('dob')}
                      error={profileErrors.dob}
                      touched={profileTouched.dob}
                    >
                      <ViDateInput
                        name="dob"
                        required={isFieldRequired('dob')}
                        value={selectedDob}
                        onChange={(val) => {
                          setSelectedDob(val);
                          if (profileTouched.dob) {
                            setProfileErrors((prev) => ({
                              ...prev,
                              dob: val ? '' : 'Vui lòng nhập Ngày sinh.',
                            }));
                          }
                        }}
                        className={`w-full px-3 py-2.5 bg-white border rounded-xl focus:outline-none focus:ring-4 transition-all ${
                          profileTouched.dob && profileErrors.dob
                            ? 'border-rose-300 focus:ring-rose-500/10 focus:border-rose-500 bg-rose-50/20'
                            : 'border-gray-200 focus:ring-indigo-500/10 focus:border-indigo-500'
                        } text-sm font-medium`}
                      />
                    </FieldWrapper>
                    <FieldWrapper label="Giới tính">
                      <select
                        name="gender"
                        defaultValue={fullData?.user_id?.gender || 'male'}
                        className="w-full px-3 py-2.5 bg-white border border-gray-200 rounded-xl focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 text-sm font-medium"
                      >
                        <option value="male">Nam</option>
                        <option value="female">Nữ</option>
                      </select>
                    </FieldWrapper>
                    <FieldWrapper
                      label="Số điện thoại"
                      required={isFieldRequired('phone')}
                      error={profileErrors.phone}
                      touched={profileTouched.phone}
                    >
                      <input
                        name="phone"
                        required={isFieldRequired('phone')}
                        type="text"
                        defaultValue={fullData?.user_id?.phone || student.phone}
                        onBlur={() => setProfileTouched((prev) => ({ ...prev, phone: true }))}
                        onChange={(e) => {
                          const val = e.target.value;
                          if (profileTouched.phone) {
                            let err = '';
                            if (!val.trim()) err = 'Vui lòng nhập Số điện thoại.';
                            else if (!/^\d{10}$/.test(val.trim())) err = 'Số điện thoại phải có đúng 10 chữ số.';
                            setProfileErrors((prev) => ({ ...prev, phone: err }));
                          }
                        }}
                        className={`w-full px-3 py-2.5 bg-white border rounded-xl focus:outline-none focus:ring-4 transition-all ${
                          profileTouched.phone && profileErrors.phone
                            ? 'border-rose-300 focus:ring-rose-500/10 focus:border-rose-500 bg-rose-50/20'
                            : 'border-gray-200 focus:ring-indigo-500/10 focus:border-indigo-500'
                        } text-sm font-medium`}
                      />
                    </FieldWrapper>
                    <FieldWrapper
                      label="CCCD / CMND"
                      required={isFieldRequired('cccd')}
                      error={profileErrors.cccd}
                      touched={profileTouched.cccd}
                    >
                      <input
                        name="cccd"
                        required={isFieldRequired('cccd')}
