const getBaseUrl = () => {
  return process.env.NEXT_PUBLIC_API_URL || 'http://103.253.21.139:5002/api/v1';
};

const BASE_URL = getBaseUrl();

let isRefreshing = false;
let refreshSubscribers: { resolve: (token: string) => void; reject: (err: any) => void }[] = [];

const subscribeTokenRefresh = (resolve: (token: string) => void, reject: (err: any) => void) => {
  refreshSubscribers.push({ resolve, reject });
};

const onTokenRefreshed = (token: string | null, err: any = null) => {
  refreshSubscribers.forEach((sub) => {
    if (err) sub.reject(err);
    else if (token) sub.resolve(token);
  });
  refreshSubscribers = [];
};

const pendingRequests = new Map<string, Promise<any>>();
const responseCache = new Map<string, { expiresAt: number; data: any }>();
const DEFAULT_GET_CACHE_TTL_MS = 3000;

export interface ApiOptions extends RequestInit {
  responseType?: 'json' | 'blob';
  cacheTtlMs?: number;
}

export const apiClient = async <T = any>(endpoint: string, options: ApiOptions = {}): Promise<T> => {
  const method = (options.method || 'GET').toUpperCase();
  const requestKey = `${method}:${endpoint}:${options.body ? JSON.stringify(options.body) : ''}`;
  const shouldUseResponseCache = method === 'GET' && options.responseType !== 'blob';
  const cacheTtlMs = options.cacheTtlMs ?? DEFAULT_GET_CACHE_TTL_MS;

  if (shouldUseResponseCache) {
    const cached = responseCache.get(requestKey);
    if (cached && cached.expiresAt > Date.now()) {
      return cached.data;
    }
  }

  if (pendingRequests.has(requestKey)) {
    return pendingRequests.get(requestKey);
  }

  const fetchPromise = (async () => {
    try {
      const result = await executeRequest(endpoint, options);
      if (shouldUseResponseCache) {
        responseCache.set(requestKey, {
          data: result,
          expiresAt: Date.now() + cacheTtlMs,
        });
      }
      return result;
    } finally {
      setTimeout(() => pendingRequests.delete(requestKey), 100);
    }
  })();

  pendingRequests.set(requestKey, fetchPromise);
  return fetchPromise;
};

const executeRequest = async (endpoint: string, options: ApiOptions = {}): Promise<any> => {
  const token = typeof window !== 'undefined' ? localStorage.getItem('token') : null;

  const headers: any = {
    ...(token ? { Authorization: `Bearer ${token}` } : {}),
    ...options.headers,
  };

  // Only set application/json if not sending FormData (to allow browser to set boundary)
  if (!(options.body instanceof FormData)) {
    headers['Content-Type'] = 'application/json';
  }

  const defaultOptions: RequestInit = {
    ...options,
    credentials: 'include',
    headers,
  };

  try {
    const response = await fetch(`${BASE_URL}${endpoint}`, defaultOptions);

    if (response.status === 401 && !endpoint.includes('/auth/refresh') && !endpoint.includes('/auth/login')) {
      if (!isRefreshing) {
        isRefreshing = true;
        try {
          const refreshRes = await fetch(`${BASE_URL}/auth/refresh`, {
            method: 'POST',
            credentials: 'include',
            headers: { 'Content-Type': 'application/json' },
          });

          if (refreshRes.ok) {
            const { data } = await refreshRes.json();
            const newToken = data.token;
            localStorage.setItem('token', newToken);
            isRefreshing = false;
            onTokenRefreshed(newToken);
          } else {
            const error = new Error('Session expired');
            isRefreshing = false;
            onTokenRefreshed(null, error);
            localStorage.removeItem('token');
            if (typeof window !== 'undefined') window.location.href = '/login';
            throw error;
          }
        } catch (err) {
          isRefreshing = false;
          onTokenRefreshed(null, err);
          throw err;
        }
      }

      return new Promise((resolve, reject) => {
        subscribeTokenRefresh(
          (newToken: string) => {
            resolve(
              apiClient(endpoint, {
                ...options,
                headers: {
                  ...options.headers,
                  Authorization: `Bearer ${newToken}`,
                },
              }),
            );
          },
          (err: any) => {
            reject(err);
          },
        );
      });
    }

    if (options.responseType === 'blob') {
      if (!response.ok) {
        const result = await response.json().catch(() => ({ message: 'Download failed' }));
        throw new Error(result.message || 'Download failed');
      }
      return await response.blob();
    }

    const result = await response.json();
    if (!response.ok) {
      const error: any = new Error(result.message || 'API Request failed');
      error.errors = result.errors;
      throw error;
    }
    return result;
  } catch (error: any) {
    throw error;
  }
};

